SELECT p.sku, p.path, p.brand, p.series, p.model, p.kind_id,
       MAX(CASE WHEN pp.key='fastener_type' THEN pp.value_text END) AS fastener_type,
       MAX(CASE WHEN pp.key='diameter_mm' THEN COALESCE(CAST(pp.value_number AS TEXT), pp.value_text) END) AS diameter_mm,
       MAX(CASE WHEN pp.key='storage_type' THEN pp.value_text END) AS storage_type
FROM products p
LEFT JOIN product_properties pp ON pp.sku = p.sku
WHERE (
    p.brand='Heco' AND p.series='Heco Zinc Plated' AND p.model='HECO 3DW-64B'
    AND p.name='Nut Bolt and Washer'
) OR (
    p.brand='Festool' AND p.series='Festool Stackable' AND p.model='SYS 3JJ-9LM'
    AND p.name='Tool Box and Bag'
)
GROUP BY p.sku, p.path, p.brand, p.series, p.model, p.kind_id
HAVING (
    p.brand='Heco' AND fastener_type='bolt' AND diameter_mm IN ('8','8.0','8 mm')
) OR (
    p.brand='Heco' AND fastener_type='bolt' AND diameter_mm IN ('10','10.0','10 mm')
) OR (
    p.brand='Heco' AND fastener_type='threaded rod'
) OR (
    p.brand='Festool' AND storage_type='tool bag'
) OR (
    p.brand='Festool' AND storage_type='parts case'
)
LIMIT 20;
